parameters.jsCode:
const chatId  = $('Telegram Trigger').first().json.message.chat.id;
const planUrl = 'https://phnjdyuwtsqqteyqetgm.supabase.co/storage/v1/object/public/bti-files/plans/' + chatId + '/plan.png?t=' + Date.now();
const NL = String.fromCharCode(10);

const prompt = [
  'Ты — эксперт по анализу планов БТИ. Проанализируй этот план.',
  'Верни только JSON (без markdown, без пояснений) в точно таком формате:',
  '{"apartment_bounds":[[x1,y1],[x2,y1],[x2,y2],[x1,y2],...],' +
  '"rooms":[{"id":"room_1","name":"Название комнаты","area":18.5,"polygon":[[x1,y1],[x2,y1],[x2,y2],[x1,y2],...],' +
  '"center":[cx,cy]},...],"total_area":45.0}',
  '',
  '(вместо x1,y1,... и cx,cy подставь реальные координаты с плана, не повторяй этот пример)',
  '',
  'ШАГ 1: определи apartment_bounds — внешний контур всей квартиры (4–6 точек [[x,y],...] в координатах 0.0–1.0).',
  'ШАГ 2: для каждого помещения дай polygon в 4–6 точках [[x,y],...], строго внутри apartment_bounds.',
  '',
  'Правила:',
  '- Назови все помещения: жилые комнаты, кухня, санузел(ы), прихожая, лоджия/балкон, кладовая',
  '- polygon: точно описывает контур помещения по стенам, 4 точки для прямоугольника, 5–6 для L-образных',
  '- Нумерация id: room_1, room_2, ... по порядку',
  '- Координаты: в диапазоне 0.0–1.0, где (0,0) — верхний левый угол плана',
  '- center: одна точка [cx, cy] — примерный визуальный центр помещения (туда, куда обычно наносят площадь или название). Это важно: одна точка точнее полигона',
  '- area: площадь помещения в м² (число под чертой или из экспликации). Если не указано — пиши null',
  '- total_area: общая площадь квартиры из плана (из строки Общая площадь или итога). Если не указано — null',
].join(NL);

const requestBody = {
  model: "gpt-4o-mini",
  messages: [{
    role: "user",
    content: [
      { type: "text", text: prompt },
      { type: "image_url", image_url: { url: planUrl, detail: "high" } }
    ]
  }],
  response_format: { type: "json_object" },
  temperature: 0.1,
  max_tokens: 2048
};

return [{ json: { chatId, planUrl, requestBodyString: JSON.stringify(requestBody) } }];

const chatId  = $('Code - Gemini Geometry Request').first().json.chatId;
const planUrl = $('Code - Gemini Geometry Request').first().json.planUrl;
const resp    = $input.first().json;

// Parse geometry response
let rooms = [];
let apartment_bounds = null;
if (resp.choices && resp.choices[0]) {
  try {
    const parsed = JSON.parse(resp.choices[0].message.content);
    rooms = parsed.rooms || [];
    apartment_bounds = parsed.apartment_bounds || null;
  } catch(e) {}
}

const roomsList = rooms.map(function(r) {
  return '- room_id: ' + r.id + ', название: ' + r.name;
}).join('\n');

const prompt =
  'Ты — эксперт по планированию фотосъёмки квартир для проверки перепланировки.\n' +
  'На этом плане БТИ расположены следующие помещения:\n' + roomsList + '\n\n' +
  'Для каждого помещения определи 1–2 точки съёмки.\n' +
  'Верни только JSON (без markdown, без пояснений):\n' +
  '{"shots":[{"shot_id":"room_1_shot_1","room_id":"room_1","room_name":"Название",'
  + '"position":"северо-западный угол","direction":"на юго-восток",'
  + '"instruction":"подробная инструкция"}]}\n\n' +
  'Правила:\n' +
  '- shot_id = room_id + "_shot_1" (и "_shot_2" если нужна вторая точка)\n' +
  '- Для просторных помещений (гостиная, спальня гот 15 кв.м) — 2 точки\n' +
  '- position: конкретный угол или место в комнате\n' +
  '- direction: направление взгляда камеры\n' +
  '- instruction: что именно показать, какие стены захватить, что важно зафиксировать\n' +
  '- Используй строго те room_id которые указаны выше, без изменений';

const requestBody = {
  model: "gpt-4o-mini",
  messages: [{
    role: "user",
    content: [
      { type: "text", text: prompt },
      { type: "image_url", image_url: { url: planUrl, detail: "high" } }
    ]
  }],
  response_format: { type: "json_object" },
  temperature: 0.1,
  max_tokens: 2048
};

return [{ json: {
  chatId,
  rooms: JSON.stringify(rooms),
  apartment_bounds: JSON.stringify(apartment_bounds),
  requestBodyString: JSON.stringify(requestBody)
} }];

const resp   = $input.first().json;
const chatId = $('Code - Gemini Geometry Request').first().json.chatId;

// API or HTTP error from shots request
if (resp.error || !resp.choices || !resp.choices[0]) {
  const msg = (resp.error && resp.error.message) || 'Ошибка API запроса Точек съёмки';
  return [{ json: { error: true, chatId: chatId, errorMsg: msg } }];
}

// Parse shots from second request
let shots = [];
try {
  const text = resp.choices[0].message.content;
  shots = JSON.parse(text).shots || [];
} catch(e) {
  return [{ json: { error: true, chatId: chatId,
    errorMsg: 'Не удалось разобрать ответ Гемини. Попробуйте загрузить более чёткий план квартиры.' } }];
}

if (!shots.length) {
  return [{ json: { error: true, chatId: chatId,
    errorMsg: 'Не удалось составить задание по плану. Убедитесь что изображение содержит план квартиры.' } }];
}

// Get rooms + bounds from geometry request (passed through shots request)
let rooms = [];
let apartment_bounds = null;
try { rooms = JSON.parse($('Code - Gemini Shots Request').first().json.rooms || '[]'); } catch(e) {}
// --- Расчёт площадей ---
// Извлекаем total_area из геометрии (если модель вернула)
let totalArea = null;
try {
  const geomResp = $('HTTP Request - Gemini Geometry').first().json;
  if (geomResp.choices && geomResp.choices[0]) {
    const geomParsed = JSON.parse(geomResp.choices[0].message.content);
    totalArea = geomParsed.total_area || null;
    // Если площади есть в геометрии — перенести их в rooms
    if (geomParsed.rooms) {
      geomParsed.rooms.forEach(function(gr) {
        const r = rooms.find(function(x) { return x.id === gr.id; });
        if (r && gr.area) r.area = gr.area;
      });
    }
  }
} catch(e) {}

// Вычисляем пропущенные площади из total_area
if (totalArea) {
  const knownSum = rooms.reduce(function(s, r) { return s + (r.area ? parseFloat(r.area) : 0); }, 0);
  const unknownRooms = rooms.filter(function(r) { return !r.area; });
  if (unknownRooms.length > 0) {
    const remaining = Math.max(0, totalArea - knownSum);
    const perRoom = Math.round((remaining / unknownRooms.length) * 10) / 10;
    unknownRooms.forEach(function(r) {
      r.area = perRoom;
      r.area_estimated = true;
    });
  }
}
try { apartment_bounds = JSON.parse($('Code - Gemini Shots Request').first().json.apartment_bounds || 'null'); } catch(e) {}

const shotsStatus = {};
shots.forEach(function(s) { shotsStatus[s.shot_id] = 'pending'; });
// No auto-request: user selects via inline keyboard buttons

// Build inline keyboard - one button per shot/room
function buildKeyboard(pendingShots) {
  return {
    rows: pendingShots.map(function(shot) {
      return {
        row: {
          buttons: [{ text: shot.room_name, additionalFields: { callback_data: shot.shot_id } }]
        }
      };
    })
  };
}
const keyboardRows = buildKeyboard(shots);

function h(s) {
  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

const roomsList = rooms.map(function(r) { return '\u2022 ' + h(r.name); }).join('\n');
const roomsText = '<b>\u041f\u043b\u0430\u043d \u043f\u0440\u043e\u0430\u043d\u0430\u043b\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043d!</b>\n\u041e\u0431\u043d\u0430\u0440\u0443\u0436\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u043c\u0435\u0449\u0435\u043d\u0438\u044f:\n' + roomsList
  + '\n\u0412\u0441\u0435\u0433\u043e \u0442\u043e\u0447\u0435\u043a \u0441\u044a\u0451\u043c\u043a\u0438: ' + shots.length;

const total    = shots.length;
const firstShot = shots[0];
const firstMsg = '\uD83D\uDCF7 <b>\u0424\u043e\u0442\u043e 1 \u0438\u0437 ' + total + '</b>\n'
  + '\uD83C\uDFE0 ' + h(firstShot.room_name) + '\n'
  + '\uD83D\uDCCD \u041f\u043e\u0437\u0438\u0446\u0438\u044f: ' + h(firstShot.position) + '\n'
  + '\u27A1\uFE0F \u041d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435: ' + h(firstShot.direction) + '\n'
  + h(firstShot.instruction) + '\n'
  + '<i>\u041e\u0442\u043f\u0440\u0430\u0432\u044c\u0442\u0435 \u0444\u043e\u0442\u043e \u043a\u0430\u043a \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442/\u0444\u0430\u0439\u043b \u2014 \u044d\u0442\u043e \u0441\u043e\u0445\u0440\u0430\u043d\u044f\u0435\u0442 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e</i>';

return [{ json: {
  error:             false,
  chatId:            chatId,
  rooms_json:        rooms,
  total_area:        totalArea,
  apartment_bounds:  apartment_bounds,
  shots_json:        shots,
  shots_status:      shotsStatus,
  rooms_text:        roomsText,
  keyboard_rows:     keyboardRows,
  total_shots:       total
} }];

const session = $('Get a row1').first().json;
const chatId  = $('Telegram Trigger').first().json.message.chat.id;

const shotsStatus = typeof session.shots_status === 'string'
  ? JSON.parse(session.shots_status) : (session.shots_status || {});
const shots = typeof session.shots_json === 'string'
  ? JSON.parse(session.shots_json) : (session.shots_json || []);

const requestedShotId = Object.keys(shotsStatus).find(function(id) { return shotsStatus[id] === 'requested'; });
if (!requestedShotId) {
  throw new Error('\u041d\u0435\u0442 \u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0439 \u0442\u043e\u0447\u043a\u0438 \u0441\u044a\u0451\u043c\u043a\u0438. \u0412\u0432\u0435\u0434\u0438\u0442\u0435 /start \u0434\u043b\u044f \u043f\u0435\u0440\u0435\u0437\u0430\u043f\u0443\u0441\u043a\u0430.');
}

const updatedStatus = Object.assign({}, shotsStatus);
updatedStatus[requestedShotId] = 'received';

const pendingShots = shots.filter(function(s) { return updatedStatus[s.shot_id] === 'pending'; });
const allDone = pendingShots.length === 0;

const receivedCount = shots.filter(function(s) { return updatedStatus[s.shot_id] === 'received'; }).length;
const total = shots.length;

let keyboardRows = null;
let nextMessage = '';

if (!allDone) {
  keyboardRows = {
    rows: pendingShots.map(function(shot) {
      return {
        row: {
          buttons: [{ text: shot.room_name, additionalFields: { callback_data: shot.shot_id } }]
        }
      };
    })
  };
  nextMessage = '\u2705 \u0424\u043e\u0442\u043e \u043f\u043e\u043b\u0443\u0447\u0435\u043d\u043e! (' + receivedCount + '/' + total + ')\n\n\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435 \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0443\u044e \u043a\u043e\u043c\u043d\u0430\u0442\u0443:';
} else {
  nextMessage = '\u2705 \u0412\u0441\u0435 \u0444\u043e\u0442\u043e\u0433\u0440\u0430\u0444\u0438\u0438 \u043f\u043e\u043b\u0443\u0447\u0435\u043d\u044b!\n\n\u041d\u0430\u0447\u0438\u043d\u0430\u044e \u0444\u0438\u043d\u0430\u043b\u044c\u043d\u044b\u0439 \u0430\u043d\u0430\u043b\u0438\u0437 \u043f\u0435\u0440\u0435\u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u043a\u0438. \u042d\u0442\u043e \u0437\u0430\u0439\u043c\u0451\u0442 1-2 \u043c\u0438\u043d\u0443\u0442\u044b...';
}

return [{
  json: {
    chatId,
    current_shot_id: requestedShotId,
    shots_status:    updatedStatus,
    all_done:        allDone,
    next_message:    nextMessage,
    keyboard_rows:   keyboardRows,
    upload_path:     'photos/' + chatId + '/' + requestedShotId + '.jpg'
  },
  binary: items[0].binary
}];

// Binary data is received from HTTP Request - Download Plan node
// n8n stores binary as base64 in item.binary[key].data
const binary = $input.first().binary;
const key = Object.keys(binary)[0];
const base64 = binary[key].data;
const mimeType = binary[key].mimeType || 'image/jpeg';

if (!base64) throw new Error('Binary data is empty — plan not found in Supabase');

return [{ json: { base64, mimeType } }];

// Загрузи эти PDF в Supabase Storage: bti-files/knowledge-base/
// normy.pdf   → Чек лист нормы перепланировок
// katalog.pdf → Каталог типовых решений перепланировок
// razmery.pdf → Чек лист допустимые размеры помещений
return [
  { json: { path: 'knowledge-base/normy.pdf',   source: 'Чек лист нормы перепланировок' } },
  { json: { path: 'knowledge-base/katalog.pdf',  source: 'Каталог типовых решений перепланировок' } },
  { json: { path: 'knowledge-base/razmery.pdf',  source: 'Чек лист допустимые размеры помещений' } }
];

const resp   = $input.first().json;
const source = $('Code - PDF Sources').item?.json?.source || 'unknown';

let chunks = [];
try {
  // OpenAI: resp.choices[0].message.content
  const raw    = resp.choices?.[0]?.message?.content || '';
  const parsed = JSON.parse(raw);
  chunks = parsed.chunks || parsed.items || (Array.isArray(parsed) ? parsed : []);
} catch(e) {
  throw new Error('\u041e\u0448\u0438\u0431\u043a\u0430 \u043f\u0430\u0440\u0441\u0438\u043d\u0433\u0430 GPT: ' + e.message);
}

if (!chunks.length) throw new Error('GPT \u0432\u0435\u0440\u043d\u0443\u043b \u043f\u0443\u0441\u0442\u043e\u0439 \u0441\u043f\u0438\u0441\u043e\u043a \u0447\u0430\u043d\u043a\u043e\u0432 \u0434\u043b\u044f: ' + source);

return chunks.map((c, i) => ({
  json: {
    source,
    title: c.title || ('\u0411\u043b\u043e\u043a ' + (i + 1)),
    chunk: c.chunk || c.text || c.content || '',
    index: i
  }
}));

const embResp = $input.first().json;
// OpenAI embeddings: { data: [{ embedding: [...1536 floats...] }] }
const embedding = embResp.data?.[0]?.embedding;
if (!embedding) throw new Error('OpenAI \u043d\u0435 \u0432\u0435\u0440\u043d\u0443\u043b embedding: ' + JSON.stringify(embResp).substring(0, 200));

const chunkData = $('Code - Parse Chunks').item.json;

return [{
  json: {
    source:    chunkData.source,
    chunk:     chunkData.chunk,
    embedding: embedding
  }
}];

// Supabase REST returns the whole array as one item
var raw = $input.first().json;
var fragments = Array.isArray(raw) ? raw : $input.all().map(function(i) { return i.json; });

if (!fragments || fragments.length === 0) {
  return [{ json: { ragContext: '', fragmentCount: 0 } }];
}

var MAX_CHUNK = 800;
var MAX_TOTAL = 20000;
var ragContext = fragments.map(function(f) {
  var text = f.content || '';
  return text.length > MAX_CHUNK ? text.slice(0, MAX_CHUNK) + '...' : text;
}).join('\n---\n');
if (ragContext.length > MAX_TOTAL) {
  ragContext = ragContext.slice(0, MAX_TOTAL) + '\n...[обрезано]';
}
return [{ json: { ragContext: ragContext, fragmentCount: fragments.length } }];

var chatId = $('Telegram Trigger').first().json.message.chat.id;
var session = $('Supabase - Get Analysis Session').first().json;
var planUrl = session.plan_url || '';
var shotsJson = session.shots_json
  ? (typeof session.shots_json === 'string' ? JSON.parse(session.shots_json) : session.shots_json)
  : [];
var shotsStatus = session.shots_status
  ? (typeof session.shots_status === 'string' ? JSON.parse(session.shots_status) : session.shots_status)
  : {};
var roomsJson = session.rooms_json
  ? (typeof session.rooms_json === 'string' ? JSON.parse(session.rooms_json) : session.rooms_json)
  : [];
var notPhoto;

var SUPABASE_STORAGE = 'https://phnjdyuwtsqqteyqetgm.supabase.co/storage/v1/object/public/bti-files/photos/';

var receivedShots = [];
for (var i = 0; i < shotsJson.length; i++) {
  var shot = shotsJson[i];
  var shotId = shot.shot_id || shot.id || '';
  var status = shotsStatus[shotId] || '';
  if (status === 'received' && shotId) {
    receivedShots.push({
      url: SUPABASE_STORAGE + chatId + '/' + shotId + '.jpg',
      room_id: shot.room_id || '',
      room_name: shot.room_name || '',
      position: shot.position || '',
      direction: shot.direction || ''
    });
  }
}

var roomsList = roomsJson.length > 0
  ? 'КОМНАТЫ (room_id → название):\n' + roomsJson.map(function(r) {
      return '- room_id: ' + r.id + ' → ' + r.name;
    }).join('\n')
  : '';

var systemPrompt =
  'Ты — опытный технический инспектор. ' +
  'Твоя задача — только наблюдение: сравни фотографии с планом БТИ и зафикcируй структурные отличия. ' +
  'НЕ классифицируй, НЕ давай рекомендации — только описывай что видишь. ' +
  'ИГНОРИРУЙ мебель, предметы интерьера и бытовую технику — они не являются структурными изменениями. ' +
  'Отвечай строго в формате JSON без markdown-обёртки. ' +
  'Если хотя бы одно из фото (кроме плана БТИ) НЕ является фотографией реального интерьера комнаты — ' +
  'возвращай {"notPhoto":true}. ' +
  'Если все фото корректны — возвращай наблюдения в формате {"observations":[...]}.';

var userText =
  (roomsList ? roomsList + '\n\n---\n\n' : '') +
  'Изображение 1 — официальный план БТИ квартиры.\n' +
  'Следующие изображения — фотографии реального состояния комнат.\n\n' +
  'ШАГ 1: Изучи план БТИ — запомни расположение стен, перегородок, дверных проёмов, санузлов.\n' +
  'ШАГ 2: Для каждой комнаты сравни фото с планом.\n' +
  'ШАГ 3: Зафикcируй только структурные отличия (снос/перенос стен, проёмы, объединение комнат, перемещение мокрых зон). Мебель, предметы интерьера и бытовая техника — НЕ изменения, их не указывай.\n\n' +
  'ФОРМАТ ОТВЕТА JSON:\n' +
  '{"observations":[{"room_id":"...","type":"...","description":"...","affected_room_ids":["room_id1","room_id2"]}]}\n\n' +
  'Допустимые type: wall_removal, wall_addition, doorway_change, room_merge, room_split, wet_zone_move, other\n' +
  'affected_room_ids: все room_id затронутых комнат.\n' +
  'Если изменений нет — возвращай {"observations":[]}.';

var contentArray = [{ type: 'text', text: userText }];
if (planUrl) {
  contentArray.push({ type: 'image_url', image_url: { url: planUrl, detail: 'high' } });
}
for (var j = 0; j < receivedShots.length; j++) {
  var s = receivedShots[j];
  var label = 'Фото ' + (j+1) + ': ' + s.room_name + ' (room_id: ' + s.room_id + '), позиция: ' + s.position + ', направление: ' + s.direction;
  contentArray.push({ type: 'text', text: label });
  contentArray.push({ type: 'image_url', image_url: { url: s.url, detail: 'auto' } });
}

var body = {
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: contentArray }
  ],
  max_tokens: 2000,
  response_format: { type: 'json_object' }
};

return [{ json: { chatId: chatId, body: JSON.stringify(body), photoCount: receivedShots.length } }];

var chatId = $('Code - Build Vision Payload').first().json.chatId;
var ragContext = $('Code - Format RAG Results').first().json.ragContext || '';

var observations = $('Code - Parse Vision Response').first().json.observations || [];

var obsText = observations.length > 0
  ? observations.map(function(o, i) {
