const data = $input.first().json; // Получаем данные
const chatId = data.chat_id; // Получаем chat_id
const shotsStatus = data.shots_status; // Получаем shots_status

// Создаем массив для инлайн кнопок
let inlineButtons = [];

// Перебираем все фотографии (shots_json)
data.shots_json.forEach((shot, index) => {
  const roomName = shot.room_name; // Название комнаты
  const shotId = shot.shot_id; // ID фото

  // Формируем текст для кнопки
  const buttonText = `Фото ${index + 1} ${roomName}`;

  // Формируем объект для инлайн кнопки
  inlineButtons.push([{
    text: buttonText,
    callback_data: shotId // Используем shot_id в callback_data
  }]);
});

// Возвращаем инлайн кнопки и другие данные
return [{
  json: {
    inline_keyboard: inlineButtons, // Убедитесь, что это массив массивов
    chat_id: chatId,
    shots_count: inlineButtons.length // Количество кнопок
  }
}];

// Получаем входные данные
const items = $input.all();

// Установите нужный `shot_id`, для которых нужно изменить статус
const shotIdsToUpdate = $('Начало процесса4').first().json.callback_query.data;

// Массив для сообщений
const messages = [];

// Обновляем статус для каждого элемента
const updatedItems = items.map(item => {
  // Извлекаем исходные данные из item
  const data = item.json;

  // Обновляем статус в shots_status с "received" на "requested" для выбранных shot_id
  const updatedShotsStatus = Object.fromEntries(
    Object.entries(data.shots_status).map(([key, value]) => {
      if (shotIdsToUpdate.includes(key)) {
        return [key, 'edit']; // Меняем статус только для выбранных снимков
      }
      return [key, value]; // Оставляем без изменений для остальных снимков
    })
  );

  // Создаем сообщение для каждого снимка, статус которого изменился
  data.shots_json.forEach((shot, index) => {
    if (shotIdsToUpdate.includes(shot.shot_id) && updatedShotsStatus[shot.shot_id] === 'edit') {
      const total = data.shots_json.length; // Общее количество снимков
      const message =`📷 Фото ${index + 1} из ${total} `+`\n🏠 ${shot.room_name} `+`\n📍 Позиция: ${shot.position} `+`\n➡️ Направление: ${shot.direction} `+`\n${shot.instruction} `+`\n\nОтправьте фото как документ/файл — это сохраняет качество. `+`\n\nЕсли вы неправильно выбрали фотографию, которую хотите заменить, нажмите кнопку "Выбрать другое фото". Если фотография выбрана правильно просто отправьте фото`;
      messages.push(message);
    }
  });

  // Возвращаем обновленный объект
  return {
    json: {
      ...data,
      shots_status: updatedShotsStatus
    }
  };
});

// Возвращаем обновленные данные и сообщения
return [
  {
    json: {
      updatedItems,
      messages
    }
  }
];

