parameters.jsCode:
// 1. Получаем ID нажатой кнопки из Telegram
const callbackData = $('Начало процесса4').first().json.callback_query.data;

// 2. Получаем данные из входящего узла
const items = $input.all();
const data = items[0].json;

const shots = data.shots_json || [];
const shotsStatus = data.shots_status || {};

// 3. ПРОВЕРКА 1: Был ли у этой конкретной фотографии статус 'received'
const isAlreadyReceived = shotsStatus[callbackData] === 'received';

// 4. ПРОВЕРКА 2: Ищем ДРУГУЮ фотографию со статусом 'requested'
let activeOtherId = null;
const isAnyOtherRequested = Object.entries(shotsStatus).some(([id, status]) => {
  if (id !== callbackData && status === 'requested') {
    activeOtherId = id; // Запоминаем ID активной комнаты
    return true;
  }
  return false;
});

// Собираем данные об этой "другой" активной комнате
let otherRoomData = null;
if (isAnyOtherRequested) {
  const otherIndex = shots.findIndex(s => s.shot_id === activeOtherId);
  if (otherIndex !== -1) {
    otherRoomData = {
      name: shots[otherIndex].room_name,
      number: otherIndex + 1
    };
  }
}

// 5. ОБНОВЛЕНИЕ СТАТУСА:
let updatedStatus = { ...shotsStatus };
if (!isAlreadyReceived && !isAnyOtherRequested) {
  updatedStatus[callbackData] = 'requested';
}

// 6. Находим данные ТЕКУЩЕЙ выбранной фотографии
const shotIndex = shots.findIndex(s => s.shot_id === callbackData);
const selectedShot = shots[shotIndex];

if (!selectedShot) {
  throw new Error('Ошибка: Фото с ID ' + callbackData + ' не найдено.');
}

// 7. Формируем текст инструкции для текущей комнаты
const total = shots.length;
const message = `📷 *Фото ${shotIndex + 1} из ${total}*
🏠 ${selectedShot.room_name}
📍 Позиция: ${selectedShot.position}
➡️ Направление: ${selectedShot.direction}
${selectedShot.instruction}

_Отправьте фото как документ/файл — это сохраняет качество._`;

// 8. Возвращаем результат
return [{
  json: {
    ...data,
    shots_status: updatedStatus,
    current_shot_id: callbackData,
    next_message: message,
    received: isAlreadyReceived,
    requested_other: isAnyOtherRequested,
    // Данные активной на данный момент комнаты
    other_room_name: otherRoomData ? otherRoomData.name : null,
    other_room_number: otherRoomData ? otherRoomData.number : null
  }
}];

