const dbToken = $input.first().json;
const incomingToken = $input.first().json.token;
const userId = $('Начало процесса4').first().json.message.chat.id;

// 1. Проверка: совпадает ли присланный токен с тем, что в БД
if (dbToken.token !== incomingToken) {
  return [{
    json: {
      access: false,
      reason: 'invalid_token'
    }
  }];
}

// 2. Проверка: привязан ли уже токен к кому-то другому
if (dbToken.chat_id && dbToken.chat_id !== userId) {
  return [{
    json: {
      access: false,
      reason: 'used_by_other'
    }
  }];
}

// 3. Результат: если проверки пройдены
// Если chat_id пустой — значит это первая активация (isNew: true)
// Если chat_id совпадает с userId — значит пользователь вернулся (isNew: false)
const isFirstActivation = !dbToken.chat_id;

return [{
  json: {
    ...dbToken,
    chat_id: userId, // записываем ID, если его не было
    access: true,
    isNew: isFirstActivation
  }
}];

