var chatId = ($('Code - Build Vision Payload1').first().json.chatId)
          || $('Get a row32').first().json.chat_id;

var resp = $input.first().json;

if(resp.error||!resp.choices||!resp.choices[0]){
  return [{json:{error:true,chatId:chatId,
    errorMsg:(resp.error&&resp.error.message)||'Ошибка GPT-4o API'}}];
}

var responseContent='';
try{responseContent=resp.choices[0].message.content;}catch(e){
  return [{json:{error:true,chatId:chatId,errorMsg:'Ошибка получения ответа: '+e.message}}];
}

var analysisResult;
try{analysisResult=JSON.parse(responseContent);}catch(e){
  analysisResult={confidence:0,changes:[],summary:'Ошибка парсинга GPT-4o: '+responseContent.substring(0,200)};
}

if(!analysisResult.changes){analysisResult.changes=[];}
if(typeof analysisResult.confidence==='undefined'){analysisResult.confidence=0.5;}
if(!analysisResult.summary){analysisResult.summary='';}

return [{json:{error:false,chatId:chatId,analysis_result:analysisResult}}];

var ar = $('Code - Parse Classification Response1').first().json.analysis_result;
var chatId = $('Code - Parse Classification Response1').first().json.chatId;
var changes = ar.changes || [];
var confidence = typeof ar.confidence === 'number' ? ar.confidence : 0.5;
var summary = ar.summary || '';
var isLow = confidence < 0.6;
var pct = Math.round(confidence * 100);

function h(s) {
  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function icon(cls) {
  if (cls === 'illegal') return '❌';
  if (cls === 'requires_approval') return '⚠️';
  return '✅';
}
function label(cls) {
  if (cls === 'illegal') return 'Незаконная перепланировка';
  if (cls === 'requires_approval') return 'Требует согласования';
  return 'Согласуемая';
}

var lines = changes.map(function(c, i) {
  return (i+1) + '. ' + icon(c.classification) + ' <b>' + h(label(c.classification)) + '</b>\n'
    + '   ' + h(c.description) + '\n'
    + '   <i>' + h(c.recommendation) + '</i>';
});

var report = '📊 <b>Результат анализа перепланировки</b>\n\n' + h(summary) + '\n\n';
if (lines.length > 0) {
  report += '<b>Обнаруженные изменения:</b>\n' + lines.join('\n\n') + '\n\n';
} else {
  report += 'Значимых изменений не обнаружено.\n\n';
}
if (isLow) {
  report += '⚠️ <i>Уверенность анализа: ' + pct + '%. Ваш запрос передан специалисту для ручной проверки.</i>\n\n';
}
report += '<i>⚠️ Результат носит информационный характер и не является юридическим заключением.</i>';

var managerMsg = '🔔 <b>Требуется ручная проверка</b>\n\n'
  + 'Chat ID: <code>' + chatId + '</code>\n'
  + 'Уверенность GPT-4o: ' + pct + '%\n\n'
  + '<b>Резюме:</b> ' + h(summary) + '\n'
  + 'Пожалуйста, проверьте анализ вручную.';

return [{ json: { chatId: chatId, report_text: report, manager_text: managerMsg,
                  confidence: confidence, is_low_confidence: isLow, has_changes: changes.length > 0 } }];

