var session = $('Get a row33').first().json;
var chatId = session.chat_id;
var rawPlanUrl = session.plan_url || '';
var planUrl = rawPlanUrl ? (rawPlanUrl.startsWith('http') ? rawPlanUrl : 'https://phnjdyuwtsqqteyqetgm.supabase.co/storage/v1/object/public/bti-files/' + rawPlanUrl) : '';
var shotsJson = session.shots_json
  ? (typeof session.shots_json==='string' ? JSON.parse(session.shots_json) : session.shots_json)
  : [];
var shotsStatusRaw = session.shots_status
  ? (typeof session.shots_status==='string' ? JSON.parse(session.shots_status) : session.shots_status)
  : [];
var shotsStatusMap = {};
if(Array.isArray(shotsStatusRaw)){
  shotsStatusRaw.forEach(function(s){ if(s.id) shotsStatusMap[s.id] = s.status; });
} else {
  shotsStatusMap = shotsStatusRaw;
}
var roomsJson = session.rooms_json
  ? (typeof session.rooms_json==='string' ? JSON.parse(session.rooms_json) : session.rooms_json)
  : [];

var SUPABASE_STORAGE = 'https://phnjdyuwtsqqteyqetgm.supabase.co/storage/v1/object/public/bti-files/photos/';

var receivedShots = [];
for(var i=0;i<shotsJson.length;i++){
  var shot=shotsJson[i];
  var shotId=shot.shot_id||shot.id||'';
  var status=shotsStatusMap[shotId]||'';
  if(status==='received'&&shotId){
    receivedShots.push({
      url: SUPABASE_STORAGE+chatId+'/'+shotId+'.jpg',
      room_id: shot.room_id||'',
      room_name: shot.room_name||'',
      position: shot.position||'',
      direction: shot.direction||''
    });
  }
}

var roomsList = roomsJson.length>0
  ? 'КОМНАТЫ (room_id → название):\n'+roomsJson.map(function(r){
      return '- room_id: '+r.id+' → '+r.name;
    }).join('\n')
  : '';

var systemPrompt =
  'Ты — опытный технический инспектор. ' +
  'Твоя задача — только наблюдение: сравни фотографии с планом БТИ и зафикcируй структурные отличия. ' +
  'НЕ классифицируй, НЕ давай рекомендации — только описывай что видишь. ' +
  'ИГНОРИРУЙ мебель, предметы интерьера и бытовую технику — они не являются структурными изменениями. ' +
  'Отвечай строго в формате JSON без markdown-обёртки.';

var userText =
  (roomsList ? roomsList+'\n\n---\n\n' : '')+
  'Изображение 1 — официальный план БТИ квартиры.\n'+
  'Следующие изображения — фотографии реального состояния комнат.\n\n'+
  'ШАГ 1: Изучи план БТИ — запомни расположение стен, перегородок, дверных проёмов, санузлов.\n'+
  'ШАГ 2: Для каждой комнаты сравни фото с планом.\n'+
  'ШАГ 3: Зафиксируй только структурные отличия (снос/перенос стен, проёмы, объединение комнат, перемещение мокрых зон). Мебель, предметы интерьера и бытовая техника — НЕ изменения, их не указывай.\n\n'+
  'ФОРМАТ ОТВЕТА JSON:\n'+
  '{"observations":[{"text":"...","room_id":"...","type":"...","description":"...","affected_room_ids":["room_id1","room_id2"]}]}\n\n'+
  'Допустимые type: wall_removal, wall_addition, doorway_change, room_merge, room_split, wet_zone_move, other\n'+
  'affected_room_ids: все room_id затронутых комнат.\n'+
  'Если изменений нет — возвращай {"observations":[]}.';

var contentArray = [{type:'text',text:userText}];
if(planUrl){contentArray.push({type:'image_url',image_url:{url:planUrl,detail:'high'}});}
for(var j=0;j<receivedShots.length;j++){
  var s=receivedShots[j];
  var lbl='Фото '+(j+1)+': '+s.room_name+' (room_id: '+s.room_id+'), позиция: '+s.position+', направление: '+s.direction;
  contentArray.push({type:'text',text:lbl});
  contentArray.push({type:'image_url',image_url:{url:s.url,detail:'auto'}});
}

var body={
  model:'gpt-4o-mini',
  messages:[
    {role:'system',content:systemPrompt},
    {role:'user',content:contentArray}
  ],
  max_tokens:2000,
  response_format:{type:'json_object'}
};

return [{json:{chatId:chatId,body:JSON.stringify(body),photoCount:receivedShots.length}}];

var chatId = $('Code - Build Vision Payload1').first().json.chatId;
var ragContext = $('Code - Format RAG Results BTI').first().json.ragContext || '';
var resp = $input.first().json;

var observations = [];
if(resp.choices&&resp.choices[0]){
  try{
    var parsed=JSON.parse(resp.choices[0].message.content);
    observations=parsed.observations||[];
  }catch(e){}
}

var obsText = observations.length>0
  ? observations.map(function(o,i){
      var ids=(o.affected_room_ids&&o.affected_room_ids.length)
        ?' (комнаты: '+o.affected_room_ids.join(', ')+')':'';
      return (i+1)+'. ['+(o.type||'other')+'] '+(o.description||'')+ids;
    }).join('\n')
  : 'Структурных изменений не обнаружено.';

var systemPrompt =
  'Ты — строгий юридический эксперт по жилищному праву России с 20-летним опытом. ' +
  'Твоя задача — классифицировать выявленные структурные изменения согласно нормативам. ' +
