  'НОРМАТИВЫ ИЗ БАЗЫ ЗНАНИЙ:\n'+ragContext+'\n\n---\n\n'+
  'ВЫЯВЛЕННЫЕ СТРУКТУРНЫЕ ИЗМЕНЕНИЯ:\n'+obsText+'\n\n---\n\n'+
  'ЗАДАНИЕ: классифицируй каждое изменение по нормативам.\n\n'+
  'ФОРМАТ ОТВЕТА JSON:\n'+
  '{"confidence":<0-1>,"changes":[{"room_id":"...","type":"...","description":"...","classification":"legal|requires_approval|illegal","recommendation":"...","affected_room_ids":["room_id1"]}],"summary":"..."}\n\n'+
  'Классификации: legal=разрешено, requires_approval=требует согласования, illegal=незаконно (несущие стены, мокрые зоны, газ)\n'+
  'affected_room_ids — ОБЯЗАТЕЛЬНЫЕ правила:\n'+
  '• wall_removal, room_merge — ВСЕГДА два room_id: оба помещения по обе стороны снесённой стены.\n'+
  '• wall_addition, room_split — ВСЕГДА два room_id: оба образовавшихся помещения.\n'+
  '• Другие типы — все room_id затронутых помещений.\n'+
  '• ЗАПРЕЩЕНО указывать один room_id для wall_removal и room_merge.\n'+
  'КРИТИЧЕСКИ ВАЖНО: все поля JSON пиши ИСКЛЮЧИТЕЛЬНО на русском языке.';

var body={
  model:'gpt-4o-mini',
  messages:[
    {role:'system',content:systemPrompt},
    {role:'user',content:userText}
  ],
  max_tokens:4000,
  response_format:{type:'json_object'}
};

return [{json:{chatId:chatId,body:JSON.stringify(body)}}];

