parameters.jsCode:
var resp = $input.first().json;
var chatId = $('Code - Build Vision Payload1').first().json.chatId;

if (resp.error || !resp.choices || !resp.choices[0]) {
  return [{ json: { error: true, chatId: chatId, notPhoto: false,
    errorMsg: (resp.error && resp.error.message) || 'Ошибка GPT-4o Vision API' } }];
}

var content = '';
try { content = resp.choices[0].message.content; } catch(e) {}

var parsed = {};
try { parsed = JSON.parse(content); } catch(e) {}

var invalidShots = Array.isArray(parsed.invalidShots) ? parsed.invalidShots : [];
var observations = parsed.observations || null;
var notPhoto = invalidShots.length > 0;

return [{ json: {
  chatId: chatId,
  notPhoto: notPhoto,
  invalidShots: invalidShots,
  observations: observations,
  raw_response: resp
} }];
